import { createContext, useContext, useEffect, useMemo, useState } from 'react';
import {
  createUserWithEmailAndPassword,
  onAuthStateChanged,
  signInWithEmailAndPassword,
  signOut,
} from 'firebase/auth';
import { onValue, ref, set } from 'firebase/database';
import { auth, database } from '../firebase';
import { isAdminRole, normalizeRole } from '../utils/authRoles';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [role, setRole] = useState('user');

  useEffect(() => {
    let unsubProfile = () => {};

    const unsubAuth = onAuthStateChanged(auth, (firebaseUser) => {
      unsubProfile();
      console.log('firebaseUser: ', firebaseUser);
      unsubProfile = () => {};
      setUser(firebaseUser);

      if (!firebaseUser) {
        setRole('user');
        setLoading(false);
        return;
      }
      
      setLoading(true); 

      const profileRef = ref(database, `users/${firebaseUser.uid}`);
      unsubProfile = onValue(
        profileRef,
        (snapshot) => {
          const val = snapshot.val();
          console.log("DB VALUE:", snapshot.val());
          console.log("PROJECT ID:", process.env.REACT_APP_FIREBASE_PROJECT_ID);
          console.log("DB URL:", process.env.REACT_APP_FIREBASE_DATABASE_URL);
          console.log("AUTH PROJECT:", auth.app.options.projectId);
          console.log("DB PROJECT:", database.app.options.projectId);
          const rawRole =
            val != null && typeof val === 'object' && 'role' in val ? val.role : null;
          setRole(normalizeRole(rawRole ?? 'user'));
          setLoading(false);
        },
        () => {
          setRole('user');
          setLoading(false);
        }
      );
    });

    return () => {
      unsubAuth();
      unsubProfile();
    };
  }, []);

  const value = useMemo(
    () => ({
      user,
      role,
      loading,
      isAdmin: Boolean(user && !loading && isAdminRole(role)),
      signUp: async (email, password) => {
        const result = await createUserWithEmailAndPassword(auth, email, password);
        await set(ref(database, `users/${result.user.uid}`), {
          email,
          role: 'user',
          createdAt: Date.now(),
        });
        return result;
      },
      login: (email, password) => signInWithEmailAndPassword(auth, email, password),
      logout: () => signOut(auth),
    }),
    [loading, role, user]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}
