/**
 * CRA sets PUBLIC_URL from package.json `homepage`. If the deployed bundle was
 * built without it, assets still load when using `"homepage": "."`, but Router
 * needs this fallback for *.github.io project sites (/repo/... ).
 */
export function getRouterBasename() {
  const trimmed = (process.env.PUBLIC_URL || '').replace(/\/$/, '');
  if (trimmed) return trimmed;

  if (typeof window === 'undefined') return undefined;

  const { hostname, pathname } = window.location;
  if (!hostname.endsWith('.github.io')) return undefined;

  const segments = pathname.split('/').filter(Boolean);
  if (segments.length === 0) return undefined;

  return `/${segments[0]}`;
}
